import{_ as n,c as i,o as t,ak as a,an as o}from"./chunks/framework.CUmoI4gT.js";const m=JSON.parse('{"title":"AireGlu Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireglu-v1-117-0.md","filePath":"aireblock-releases/aireglu-v1-117-0.md","lastUpdated":1779093194000}'),s={name:"aireblock-releases/aireglu-v1-117-0.md"};function l(c,e,r,d,u,h){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="aireglu-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+o+'"> AireGlu Release Notes</span> <a class="header-anchor" href="#aireglu-release-notes" aria-label="Permalink to “AireGlu Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.117.0<br><strong>Release Date:</strong> 21st May 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Office 365 Email Connection Support — GLU-3093</li><li>Open Endpoints in a New Tab — GLU-2856</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Disable Individual Endpoint Tasks — GLU-299</li><li>Hide Git-Synchronised Endpoints — GLU-1536</li><li>Email Task Authentication Settings — GLU-3096</li><li>Connection Management UI — GLU-3099</li><li>Unified Connections Framework — GLU-3101</li><li>OAuth Connections in New Framework — GLU-3111</li><li>Delete Connection Support — GLU-3113</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Malicious File Upload Prevention — GLU-3079</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="office-365-email-connection-support-glu-3093" tabindex="-1">Office 365 Email Connection Support (GLU-3093) <a class="header-anchor" href="#office-365-email-connection-support-glu-3093" aria-label="Permalink to “Office 365 Email Connection Support (GLU-3093)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new Office 365 email connection type has been added, allowing tenants to configure email sending via Microsoft&#39;s OAuth-based mail API. The connection requires a Tenant ID, Application ID, client secret, and sender email address to be configured.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now send emails from your endpoints using your organisation&#39;s Office 365 account, giving you a more secure and manageable alternative to SMTP credentials. Once configured on the Connections page, the Office 365 connection can be selected directly from email tasks.</p></div><h4 id="open-endpoints-in-a-new-tab-glu-2856" tabindex="-1">Open Endpoints in a New Tab (GLU-2856) <a class="header-anchor" href="#open-endpoints-in-a-new-tab-glu-2856" aria-label="Permalink to “Open Endpoints in a New Tab (GLU-2856)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Endpoints can now be opened in a new browser tab using middle-click or right-click and selecting &quot;Open in new tab&quot;, following standard browser conventions.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now work with multiple endpoints side by side without losing your place in the endpoints list. No more navigating back and forth to compare or edit several endpoints at once.</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="disable-individual-endpoint-tasks-glu-299" tabindex="-1">Disable Individual Endpoint Tasks (GLU-299) <a class="header-anchor" href="#disable-individual-endpoint-tasks-glu-299" aria-label="Permalink to “Disable Individual Endpoint Tasks (GLU-299)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A toggle has been added to each task in the endpoint pipeline editor, allowing individual tasks to be enabled or disabled. Disabled tasks are visually greyed out and are skipped at runtime. Usage data will reflect that a task was disabled rather than executed.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now turn off specific steps in an endpoint pipeline without removing them entirely. This makes it easier to test, debug, or temporarily bypass a task without losing its configuration.</p></div><h4 id="hide-git-synchronised-endpoints-glu-1536" tabindex="-1">Hide Git-Synchronised Endpoints (GLU-1536) <a class="header-anchor" href="#hide-git-synchronised-endpoints-glu-1536" aria-label="Permalink to “Hide Git-Synchronised Endpoints (GLU-1536)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A toggle has been added to the endpoints list allowing users to show or hide git-synchronised endpoints. All endpoints are shown by default, and the user&#39;s preference is persisted in a manner consistent with other UI toggles such as the Group View option.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>If your environment contains many repository-synchronised endpoints that you don&#39;t need to interact with directly, you can now hide them to focus on the endpoints you actively configure. The toggle is easy to switch if you need to view synchronised endpoints again.</p></div><h4 id="email-task-authentication-settings-glu-3096" tabindex="-1">Email Task Authentication Settings (GLU-3096) <a class="header-anchor" href="#email-task-authentication-settings-glu-3096" aria-label="Permalink to “Email Task Authentication Settings (GLU-3096)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>SMTP settings within the email task have been moved to a dedicated Authentication tab. The authentication method dropdown now offers clearer options: default SMTP settings, custom SMTP settings, or a connection link (for future use).</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Email task configuration is now better organised, making it easier to find and manage authentication settings. The cleaner layout prepares the way for connecting email tasks to named email connections in future releases.</p></div><h4 id="connection-management-ui-glu-3099" tabindex="-1">Connection Management UI (GLU-3099) <a class="header-anchor" href="#connection-management-ui-glu-3099" aria-label="Permalink to “Connection Management UI (GLU-3099)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The Connections page has been updated with a new &quot;Add Connection&quot; dialogue that supports multiple connection types. The design follows the same pattern as the Add Task dialogue for a consistent experience.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Adding new connections is now more intuitive, with a guided interface that clearly presents the available connection types and walks you through configuration step by step.</p></div><h4 id="unified-connections-framework-glu-3101" tabindex="-1">Unified Connections Framework (GLU-3101) <a class="header-anchor" href="#unified-connections-framework-glu-3101" aria-label="Permalink to “Unified Connections Framework (GLU-3101)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new unified connections collection has been introduced to store all connection types — including OAuth and email connections — in a single, consistent data model. Existing OAuth connections have been migrated into this new framework. The model supports type-based filtering so that tasks can surface only the appropriate connection options.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Connections across AireGlu are now managed in one place with a consistent structure. This lays the groundwork for supporting additional connection types — such as Office 365 and Gmail — and makes it easier to filter and select the right connection when configuring tasks.</p></div><h4 id="oauth-connections-in-new-framework-glu-3111" tabindex="-1">OAuth Connections in New Framework (GLU-3111) <a class="header-anchor" href="#oauth-connections-in-new-framework-glu-3111" aria-label="Permalink to “OAuth Connections in New Framework (GLU-3111)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>OAuth connections have been fully integrated into the new unified connections framework, ensuring they behave consistently alongside other connection types such as Office 365 email connections.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your existing OAuth connections continue to work as before, now benefiting from the improved connection management infrastructure introduced in this release.</p></div><h4 id="delete-connection-support-glu-3113" tabindex="-1">Delete Connection Support (GLU-3113) <a class="header-anchor" href="#delete-connection-support-glu-3113" aria-label="Permalink to “Delete Connection Support (GLU-3113)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Support for deleting connections via the API has been added, enabling connections to be removed from the unified connections collection when they are no longer needed.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now remove connections that are no longer in use directly from the Connections page, keeping your connection list clean and manageable.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="malicious-file-upload-prevention-glu-3079" tabindex="-1">Malicious File Upload Prevention (GLU-3079) <a class="header-anchor" href="#malicious-file-upload-prevention-glu-3079" aria-label="Permalink to “Malicious File Upload Prevention (GLU-3079)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A vulnerability identified during penetration testing that allowed malicious file content to be uploaded has been resolved. File upload validation has been strengthened to reject potentially harmful content.</p></div>',46)])])}const f=n(s,[["render",l]]);export{m as __pageData,f as default};
